@app.route('/oauth/token', methods=['POST'])
def issue_token():
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    grant_type = request.form.get('grant_type')
    scope = request.form.get('scope', 'read')
    
    if grant_type != 'client_credentials':
        return jsonify({'error': 'unsupported_grant_type'}), 400
    
    if not client_id or not client_secret:
        return jsonify({'error': 'invalid_client'}), 401
    
    expected_secret = os.environ.get(f'CLIENT_SECRET_{client_id}')
    if not expected_secret or not secrets.compare_digest(client_secret, expected_secret):
        return jsonify({'error': 'invalid_client'}), 401
    
    scopes = [s.strip() for s in scope.split(',') if s.strip()]
    allowed_scopes = {'read', 'write', 'admin'}
    scopes = [s for s in scopes if s in allowed_scopes]
    
    if not scopes:
        scopes = ['read']
    
    user_id = f'client_{client_id}'
    token = create_access_token(client_id, user_id, scopes, expires_in=3600)
    
    return jsonify({
        'access_token': token,
        'token_type': 'Bearer',
        'expires_in': 3600,
        'scope': ','.join(scopes)
    }), 200

